class Solution {
public:
    int minChanges(int n, int k) {
        if (n == k) return 0;
        int changes = 0;
        for (int i = 0; i < 32; ++i) {
            bool n_bit = (n >> i) & 1;
            bool k_bit = (k >> i) & 1;
            if (k_bit == 1 && n_bit == 0) return -1;
            if (n_bit == 1 && k_bit == 0) ++changes;
        }
        return changes;
    }
};

